queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?novels a :Novel .
    ?novels p:title ?title .
    ?novels p:language ?language_f .
    FILTER(STR(?language_f) = "Italian")
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?poems a :Poems .
    ?poems p:poem_name ?poem_name .
    ?poems p:language ?language_f .
    FILTER(STR(?language_f) = "Italian")
    BIND(?poem_name AS ?o0)
  }
}

